  ('generalpolice-94737317-moex-00672', 'generalpolice-94737317', 'generalpolice-94737317-moex-110-9b499a9f', 'sub-generalpolice-94737317-02', NULL, 'single_choice', '有關良導體金屬殼的靜電學性質，下列敘述何者錯誤？', '["在靜電平衡條件下，電荷只分布在金屬殼的表面", "在靜電平衡條件下，若金屬殼內置有帶電體，則帶電體的電場無法對金屬殼外部產生影響", "在靜電平衡條件下，金屬殼內任何一處都是等電位，且表面電荷一定會均勻分布", "在金屬殼內放置一手機，則該手機無法接收到金屬殼外手機撥打的訊號"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:49+00:00", "source_pdf_sha1": "7833ba369bd8", "answer_pdf_sha1": "495d05b89d6c", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "402", "s": "1706", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "普通物理學概要與普通化學概要", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "消防警察人員"}'::jsonb, NULL),
